import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import {
  Trash2,
  Download,
  Archive,
  Calendar,
  ShieldCheck,
  Eye,
  X,
  BarChart3,
  AlignLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = res.data?.data || res.data || [];
      setHistory(Array.isArray(data) ? data.filter(item => item && item.id) : []);
    } catch {
      toast.error('DATABASE_OFFLINE');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete strategy permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success('DELETED');
    } catch {
      toast.error('DELETE_FAILED');
    }
  };

  const handleDownload = async (item) => {
    try {
      const res = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = URL.createObjectURL(new Blob([res.data], { type: 'application/pdf' }));
      const a = document.createElement('a');
      a.href = url;
      a.download = `Strategy_${item.id}.pdf`;
      a.click();
    } catch {
      toast.error('EXPORT_ERROR');
    }
  };

  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'auto';
    return () => (document.body.style.overflow = 'auto');
  }, [selectedItem]);

  if (loading) return <div style={centerStyle}>INITIALIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}><Archive size={22} color="var(--accent-primary)" /> Strategy Vault</h2>
        <div style={vaultBadge}><BarChart3 size={14} /> {history.length} Nodes</div>
      </div>

      <div style={listStyle}>
        {history.map(item => (
          <div key={item.id} style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '20px' }}>
                <span style={metaText}><Calendar size={14} /> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={14} /> Risk: {item.risk_score ?? 'N/A'}</span>
              </div>
              <div style={cardActions}>
                <button style={iconBtn} onClick={() => setSelectedItem(item)}><Eye size={18} /></button>
                <button style={iconBtn} onClick={() => handleDownload(item)}><Download size={18} /></button>
                <button style={deleteBtn} onClick={() => handleDelete(item.id)}><Trash2 size={18} /></button>
              </div>
            </div>
            <h4 style={titleStyle}>{item.goal || 'Untitled Strategy'}</h4>
            <div className="markdown-vault">
              <ReactMarkdown>{item.summary || '_No summary._'}</ReactMarkdown>
            </div>
          </div>
        ))}
      </div>

      {/* ── OLED DARK MODAL ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader(isDark)}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button style={closeBtn} onClick={() => setSelectedItem(null)}><X size={20} /></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal || 'Untitled Strategy'}</h3>
              <p style={modalLabel}><AlignLeft size={14} /> AGENTIC_RATIONALE</p>
              <div className="markdown-vault description-box">
                <ReactMarkdown>{selectedItem.rationale || '_No rationale._'}</ReactMarkdown>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault p { color: var(--text-primary); font-size: 0.95rem; line-height: 1.6; }
        .description-box p { color: var(--text-primary) !important; opacity: 1 !important; }
        .reveal-node { animation: fadeIn 0.3s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ── STYLES ── */
const containerStyle = { padding: '2.5rem 1.5rem', maxWidth: '1000px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '2rem', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1rem' };
const headerStyle = { display: 'flex', alignItems: 'center', gap: '10px', fontSize: '1.4rem', fontWeight: 800, color: 'var(--text-primary)' };
const vaultBadge = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', fontWeight: 700, color: 'var(--accent-primary)' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const cardStyle = { padding: '1.5rem', borderRadius: '12px', border: '1px solid var(--surface-border)', background: 'var(--bg-input)' };
const cardMeta = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const metaText = { fontSize: '0.8rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '6px' };
const riskTag = { ...metaText, color: 'var(--accent-primary)', fontWeight: 700 };
const cardActions = { display: 'flex', gap: '12px' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };
const titleStyle = { fontSize: '1.1rem', fontWeight: 700, marginBottom: '0.8rem', color: 'var(--text-primary)' };
const centerStyle = { height: '60vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-primary)', fontFamily: 'monospace' };

const modalOverlay = (isDark) => ({
  position: 'fixed', inset: 0,
  background: isDark ? 'rgba(0, 0, 0, 0.95)' : 'rgba(255, 255, 255, 0.8)',
  backdropFilter: 'blur(12px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999
});

const modalContent = (isDark) => ({
  width: '90%', maxWidth: '800px',
  background: isDark ? '#000000' : '#ffffff', // PURE BLACK IN DARK MODE
  border: `1px solid ${isDark ? '#333' : 'var(--surface-border)'}`,
  borderRadius: '16px', maxHeight: '85vh', display: 'flex', flexDirection: 'column', overflow: 'hidden'
});

const modalHeader = (isDark) => ({
  padding: '1rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
  borderBottom: `1px solid ${isDark ? '#222' : '#eee'}`
});

const modalId = { fontSize: '0.7rem', fontWeight: 700, color: 'var(--accent-primary)', fontFamily: 'monospace' };
const modalBody = { padding: '2rem', overflowY: 'auto' };
const modalTitle = { fontSize: '1.4rem', fontWeight: 800, marginBottom: '1.5rem', color: 'var(--text-primary)' };
const modalLabel = { fontSize: '0.75rem', fontWeight: 700, color: 'var(--accent-primary)', marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' };
const closeBtn = { background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' };

export default VaultPage;
